export interface EquipmentStats {
  hpBase: number;
  hpPerTier: number;
  manaBase: number;
  manaPerTier: number;
  critBase: number;
  critPerTier: number;
  blockBase: number;
  blockPerTier: number;
  defenseBase: number;
  defensePerTier: number;
}

export interface EquipmentItem {
  id: string;
  name: string;
  type: "Helm" | "Shoulder" | "Chest" | "Hands" | "Feet" | "Ring" | "Necklace" | "Relic" | "Offhand";
  material: "Cloth" | "Leather" | "Metal" | "Gem";
  lore: string;
  stats: EquipmentStats;
  passive: string;
  attribute: string;
  effect: string;
  proc: string;
  setBonus: string;
}

function parseStats(hp: string, mana: string, crit: string, block: string, defense: string): EquipmentStats {
  const parse = (s: string) => {
    const [base, perTier] = s.split(" +").map(n => parseFloat(n) || 0);
    return { base, perTier };
  };
  return {
    hpBase: parse(hp).base,
    hpPerTier: parse(hp).perTier,
    manaBase: parse(mana).base,
    manaPerTier: parse(mana).perTier,
    critBase: parse(crit).base,
    critPerTier: parse(crit).perTier,
    blockBase: parse(block).base,
    blockPerTier: parse(block).perTier,
    defenseBase: parse(defense).base,
    defensePerTier: parse(defense).perTier,
  };
}

