export const ALL_EQUIPMENT = [
  ...CLOTH_EQUIPMENT,
  ...LEATHER_EQUIPMENT,
  ...METAL_EQUIPMENT,
  ...GEM_EQUIPMENT,
];

export function getEquipmentByMaterial(material: string): EquipmentItem[] {
  switch (material) {
    case "Cloth": return CLOTH_EQUIPMENT;
    case "Leather": return LEATHER_EQUIPMENT;
    case "Metal": return METAL_EQUIPMENT;
    case "Gem": return GEM_EQUIPMENT;
    default: return ALL_EQUIPMENT;
  }
}

export function getEquipmentByType(type: string): EquipmentItem[] {
  return ALL_EQUIPMENT.filter(e => e.type === type);
}

export function getEquipmentBySet(setName: string): EquipmentItem[] {
  return ALL_EQUIPMENT.filter(e => e.name.toLowerCase().includes(setName.toLowerCase()));
}

export function calculateStatsAtTier(item: EquipmentItem, tier: number): { hp: number; mana: number; crit: number; block: number; defense: number } {
  const tierBonus = tier - 1;
  return {
    hp: Math.round(item.stats.hpBase + (item.stats.hpPerTier * tierBonus)),
    mana: Math.round(item.stats.manaBase + (item.stats.manaPerTier * tierBonus)),
    crit: +(item.stats.critBase + (item.stats.critPerTier * tierBonus)).toFixed(1),
    block: +(item.stats.blockBase + (item.stats.blockPerTier * tierBonus)).toFixed(1),
    defense: Math.round(item.stats.defenseBase + (item.stats.defensePerTier * tierBonus)),
  };
}
